import{_ as p,o as e,c as o,U as r}from"./chunks/framework.82e57da9.js";const c=JSON.parse('{"title":"Midjourney使用问题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/AI绘画工具/Midjourney AI绘画工具/Midjourney使用问题.md","filePath":"Document/AI绘画工具/Midjourney AI绘画工具/Midjourney使用问题.md","lastUpdated":1689934506000}'),n={name:"Document/AI绘画工具/Midjourney AI绘画工具/Midjourney使用问题.md"},i=r('<h1 id="midjourney使用问题" tabindex="-1">Midjourney使用问题 <a class="header-anchor" href="#midjourney使用问题" aria-label="Permalink to &quot;Midjourney使用问题&quot;">​</a></h1><p>问题一：Midjourney是什么？</p><p>Midjourney 是 AI 生成算图工具，输入文字就会自动产生图像，目前架设在Discord频道上。</p><p>问题二：Discord频道是什么？</p><p>Discord是国外的一个社群工具，类似QQ，Discord频道就类似QQ群。</p><p>Midjourney的使用方式是：通过给频道内的聊天机器人发送对应文本，聊天机器人返回对应的图片。</p><p>所以想用Midjourney，就要先注册一个Discord，然后进入Midjourney的Discord频道。</p><p>问题三：Midjourney图片版权归属？</p><p>版权归属于创作者，所以不要看人家的图漂亮就拿来用，自己用关键词去生成！</p><p>问题四：Midjourney对硬件配置有要求吗？</p><p>没有任何要求，但因为内容在外网，只要求可以课学上网即可。</p><p>问题五：经常看到prompt，prompt到底是什么？</p><p>其实就是关键字（提示词），是你提供给Midjourney的文本，Midjourney依靠文本提示词来生成图片，Midjourney<strong>关键词就是AI绘图的灵魂</strong>，它直接影响你出图图片的质量！</p><p>大家记住：即使Midjourney关键词一样（修改任意一个元素 后），也没关系，只要是你自己生成的图品，你才有权限使用：</p><p>问题六：Midjourney免费吗？Midjourney要钱吗？</p><p>Midjourney免费，但每个账号只能生成25张图片。</p><p>到达图片上限后，需要购买Midjourney会员。</p><p>你要是没有快速出图需要，可以注册多个账户来免费使用Midjourney。</p><p>问题七：Midjourney会员多少钱？</p><p>主要分为：</p><p>基础版会员（10美金一个月，一个月可以制作200张图）</p><p>标准版会员（30美金一个月，无限制作图，有15小时快速出图模式）</p><p>问题八：Midjourney如何购买会员？</p><p>需要使用可以支持外币支付的信用卡进行购买！</p><p>问题九：Midjourney社区里，我为什么无法查看别人的作品和prompt？</p><p>因为你需要先升级为Midjourney会员，才可以使用社区功能，查看更多作品。</p><p>问题十：Fast模式和Relax模式有什么差别？</p><p>在输入框输入“/fast”或者“/relax” 即可切换模式，默认是fast模式</p><p>fast模式：无需排队，发送prompt立马绘图，（30美金会员，支持15小时Fast模式）</p><p>relax模式：需要排队，排队完成自动生成。</p><p>问题十一：如何查看自己生成过的历史作品？</p><p>进入Midjourney网站，点击右边的“sign in”进入自己的主页。在这里可以找到图片的描述、位置以及下载。</p>',32),d=[i];function t(a,u,s,j,y,M){return e(),o("div",null,d)}const m=p(n,[["render",t]]);export{c as __pageData,m as default};
